import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { MessageCircle, X, Send, Bot, User, Crown, Lock } from "lucide-react";
import PaymentModal from "./PaymentModal";

// Number of free messages per day
const FREE_LIMIT = 10;

// Replace this with the user's actual API key via .env later
// Using a placeholder for now that they will replace
const GEMINI_API_URL = "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=";

interface Message {
  id: string;
  sender: "user" | "bot";
  text: string;
}

const AIBotWidget = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { id: "1", sender: "bot", text: "Hi! I'm your AI Counselor. Ask me anything about JEE cutoffs, colleges, or rank prediction!" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [msgCount, setMsgCount] = useState(0);
  const [paymentOpen, setPaymentOpen] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Load chat limit from localStorage
  useEffect(() => {
    const today = new Date().toDateString();
    const storedDate = localStorage.getItem("chatDate");
    const storedCount = localStorage.getItem("chatCount");
    const storedVersion = localStorage.getItem("chatVersion");

    // Reset if new day OR if limit version changed (force reset on upgrade)
    if (storedDate !== today || storedVersion !== "v2") {
      localStorage.setItem("chatDate", today);
      localStorage.setItem("chatCount", "0");
      localStorage.setItem("chatVersion", "v2");
      setMsgCount(0);
    } else if (storedCount) {
      setMsgCount(parseInt(storedCount, 10));
    }
  }, []);

  // Set chat count when updated
  const incrementMsgCount = () => {
    const newCount = msgCount + 1;
    setMsgCount(newCount);
    localStorage.setItem("chatCount", String(newCount));
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || msgCount >= FREE_LIMIT) return;

    const userMessage = input.trim();
    setInput("");
    setMessages(prev => [...prev, { id: Date.now().toString(), sender: "user", text: userMessage }]);
    incrementMsgCount();
    setIsLoading(true);

    try {
      const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
      if (!apiKey) {
        setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: "bot", 
          text: "ΓÜá∩╕Å API Key missing! The owner needs to add VITE_GEMINI_API_KEY in the .env file for the AI to work." 
        }]);
        setIsLoading(false);
        return;
      }

      const response = await fetch(GEMINI_API_URL + apiKey, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          contents: [{ parts: [{ text: `You are an expert JEE college counselor for a website named RankEdge. Be very concise, helpful, and answer in short paragraphs. Never use markdown formatting like ** or #. Keep responses under 150 words. The user is asking: ${userMessage}` }] }],
          generationConfig: { maxOutputTokens: 1024 }
        })
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data?.error?.message || `HTTP Error ${response.status}`);
      }

      if (data.candidates && data.candidates[0]) {
        // Gemini 2.5 may return multiple parts (thinking + response)
        // We want the last text part which contains the actual answer
        const parts = data.candidates[0].content?.parts || [];
        const textParts = parts.filter((p: any) => p.text && !p.thought);
        const botText = textParts.length > 0 
          ? textParts[textParts.length - 1].text 
          : parts[parts.length - 1]?.text || "I couldn't generate a response. Please try asking again.";
        setMessages(prev => [...prev, { id: Date.now().toString(), sender: "bot", text: botText }]);
      } else {
        throw new Error("Invalid response format from AI");
      }
    } catch (error: any) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        sender: "bot", 
        text: `Error connecting to AI: ${error.message || "Please try again later!"}` 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <PaymentModal isOpen={paymentOpen} onClose={() => setPaymentOpen(false)} />

      {/* Floating Button */}
      <AnimatePresence>
        {!isOpen && (
          <motion.button
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0, opacity: 0 }}
            onClick={() => setIsOpen(true)}
            className="fixed bottom-6 right-6 z-50 p-4 rounded-full gradient-btn shadow-[0_0_30px_hsl(217_91%_60%/0.4)] hover:shadow-[0_0_40px_hsl(217_91%_60%/0.6)] transition-all group"
          >
            <Bot className="w-6 h-6 text-primary-foreground group-hover:scale-110 transition-transform" />
            {msgCount < FREE_LIMIT && (
              <span className="absolute -top-1 -right-1 flex h-4 w-4">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-secondary opacity-75"></span>
                <span className="relative inline-flex rounded-full h-4 w-4 bg-secondary border border-background"></span>
              </span>
            )}
          </motion.button>
        )}
      </AnimatePresence>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.9 }}
            className="fixed bottom-6 right-6 z-50 w-[92vw] sm:w-[480px] md:w-[520px] h-[75vh] sm:h-[600px] max-h-[85vh] glass-card border flex flex-col shadow-2xl overflow-hidden rounded-2xl"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-border/50 bg-muted/30">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                  <Bot className="w-4 h-4 text-primary" />
                </div>
                <div>
                  <h3 className="text-sm font-semibold text-foreground">RankEdge AI Counselor</h3>
                  <p className="text-[10px] text-muted-foreground flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span> Online
                  </p>
                </div>
              </div>
              <button 
                onClick={() => setIsOpen(false)}
                className="p-2 hover:bg-muted rounded-full transition-colors text-muted-foreground hover:text-foreground"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            {/* Chat Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-background/50">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.sender === "user" ? "justify-end" : "justify-start"}`}>
                  <div className={`flex gap-2 max-w-[85%] ${msg.sender === "user" ? "flex-row-reverse" : "flex-row"}`}>
                    <div className={`w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0 mt-1 ${msg.sender === "user" ? "bg-accent/20" : "bg-primary/20"}`}>
                      {msg.sender === "user" ? <User className="w-3.5 h-3.5 text-accent" /> : <Bot className="w-3.5 h-3.5 text-primary" />}
                    </div>
                    <div className={`px-4 py-2.5 rounded-2xl text-sm ${
                      msg.sender === "user" 
                        ? "bg-accent/10 border border-accent/20 text-accent-foreground rounded-tr-sm" 
                        : "bg-muted border border-border/50 text-foreground rounded-tl-sm"
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                </div>
              ))}

              {isLoading && (
                <div className="flex justify-start">
                  <div className="flex gap-2 max-w-[85%]">
                    <div className="w-6 h-6 rounded-full bg-primary/20 flex items-center justify-center flex-shrink-0 mt-1">
                      <Bot className="w-3.5 h-3.5 text-primary" />
                    </div>
                    <div className="px-4 py-3 rounded-2xl bg-muted border border-border/50 rounded-tl-sm flex gap-1 items-center">
                      <motion.div className="w-1.5 h-1.5 bg-primary/50 rounded-full" animate={{ y: [0, -4, 0] }} transition={{ repeat: Infinity, delay: 0 }} />
                      <motion.div className="w-1.5 h-1.5 bg-primary/50 rounded-full" animate={{ y: [0, -4, 0] }} transition={{ repeat: Infinity, delay: 0.15 }} />
                      <motion.div className="w-1.5 h-1.5 bg-primary/50 rounded-full" animate={{ y: [0, -4, 0] }} transition={{ repeat: Infinity, delay: 0.3 }} />
                    </div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input Limit Tracker */}
            <div className="px-4 py-2 bg-muted/20 border-t border-border/50 text-xs flex justify-between items-center text-muted-foreground">
              <span>Remaining free queries:</span>
              <span className={`font-bold ${FREE_LIMIT - msgCount <= 1 ? "text-red-400" : "text-foreground"}`}>
                {FREE_LIMIT - msgCount} / {FREE_LIMIT}
              </span>
            </div>

            {/* Paywall Overlay if locked */}
            {msgCount >= FREE_LIMIT ? (
              <div className="p-4 bg-muted/80 backdrop-blur-md border-t border-border/50 flex flex-col items-center justify-center absolute bottom-0 left-0 right-0 h-32">
                <Lock className="w-5 h-5 text-accent mb-2" />
                <p className="text-xs text-foreground mb-3 text-center font-medium">Daily limit reached. Unlock unlimited AI counseling!</p>
                <button 
                  onClick={() => setPaymentOpen(true)}
                  className="w-full py-2 bg-gradient-to-r from-orange-500 to-amber-500 rounded-lg text-white font-bold text-sm shadow-[0_0_15px_rgba(249,115,22,0.4)] hover:scale-[1.02] transition-transform flex items-center justify-center gap-2"
                >
                  <Crown className="w-4 h-4" /> Go Premium for Γé╣49
                </button>
              </div>
            ) : (
              /* Normal Input Area */
              <div className="p-3 border-t border-border/50 bg-background/80 backdrop-blur-sm">
                <div className="flex items-end gap-2 bg-muted/30 border border-border/50 rounded-xl p-1 pr-2">
                  <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && !e.shiftKey) {
                        e.preventDefault();
                        handleSend();
                      }
                    }}
                    placeholder="Ask about colleges..."
                    className="flex-1 max-h-32 min-h-[44px] bg-transparent resize-none p-3 text-sm focus:outline-none placeholder:text-muted-foreground/50"
                    rows={1}
                  />
                  <button
                    onClick={handleSend}
                    disabled={!input.trim() || isLoading}
                    className="p-2 mb-1 bg-primary text-primary-foreground rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-primary/90 transition-colors"
                  >
                    <Send className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default AIBotWidget;

import { motion } from "framer-motion";
import { getHistoricalData } from "@/lib/rankPredictor";
import {
  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Legend, LineChart, Line
} from "recharts";

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="glass-card p-3 md:p-4 !bg-background/95 border-border shadow-xl">
        <p className="font-display font-semibold text-foreground mb-2 pb-2 border-b border-border/50">
          Score: {label} Marks
        </p>
        {payload.map((entry: any, index: number) => (
          <div key={index} className="flex items-center justify-between gap-4 text-sm my-1.5">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color }} />
              <span className="text-muted-foreground">{entry.name}</span>
            </div>
            <span className="font-semibold text-foreground" style={{ color: entry.color }}>
              {entry.name.includes("Rank") 
                ? `#${entry.value.toLocaleString("en-IN")}`
                : `${entry.value}%ile`
              }
            </span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};

const AnalyticsSection = () => {
  const data = getHistoricalData();

  return (
    <section id="analytics" className="py-20 bg-muted/20 relative overflow-hidden">
      {/* Decorative glows */}
      <div className="absolute top-1/2 left-0 w-96 h-96 bg-primary/10 rounded-full blur-[120px] -translate-x-1/2 -translate-y-1/2" />
      <div className="absolute top-1/2 right-0 w-96 h-96 bg-accent/10 rounded-full blur-[120px] translate-x-1/2 -translate-y-1/2" />

      <div className="container mx-auto px-4 relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-12"
        >
          <div className="inline-block mb-3 px-3 py-1 rounded-full border border-border bg-transparent text-xs font-semibold text-muted-foreground">
            Data Insights
          </div>
          <h2 className="text-3xl md:text-5xl font-display font-bold text-foreground mb-4">
            JEE Main <span className="gradient-text">Trend Analytics</span>
          </h2>
          <p className="text-muted-foreground max-w-2xl mx-auto">
            Compare how marks mapped to percentiles and ranks across different years. Notice the shift in competition through our dynamic visualizations. 
          </p>
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
          {/* Chart 1: Score vs Percentile */}
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="glass-card p-6 md:p-8 hover:border-primary/50 transition-colors group"
          >
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-xl font-display font-semibold text-foreground">Score vs Percentile</h3>
                <p className="text-sm text-muted-foreground mt-1">2024 vs 2025 Prediction</p>
              </div>
            </div>
            <div className="h-[300px] md:h-[400px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--muted-foreground)/0.15)" vertical={false} />
                  <XAxis 
                    dataKey="score" 
                    tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 12 }} 
                    axisLine={false} 
                    tickLine={false}
                    label={{ value: "Marks out of 300", position: "insideBottom", offset: -5, fill: "hsl(var(--muted-foreground))" }} 
                  />
                  <YAxis 
                    domain={[40, 100]} 
                    tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 12 }} 
                    axisLine={false} 
                    tickLine={false} 
                  />
                  <Tooltip content={<CustomTooltip />} cursor={{ stroke: 'hsl(var(--border))', strokeWidth: 2, strokeDasharray: '5 5' }} />
                  <Legend wrapperStyle={{ paddingTop: '20px' }} />
                  
                  <Line 
                    type="monotone" 
                    dataKey="percentile25" 
                    name="2025 (Predicted)" 
                    stroke="hsl(var(--primary))" 
                    strokeWidth={3} 
                    dot={false}
                    activeDot={{ r: 6, strokeWidth: 0, fill: "hsl(var(--primary))" }} 
                  />
                  <Line 
                    type="monotone" 
                    dataKey="percentile24" 
                    name="2024 (Actual)" 
                    stroke="hsl(var(--secondary))" 
                    strokeWidth={3} 
                    dot={false}
                    strokeDasharray="5 5"
                    activeDot={{ r: 6, strokeWidth: 0, fill: "hsl(var(--secondary))" }} 
                  />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </motion.div>

          {/* Chart 2: Score vs Rank */}
          <motion.div
            initial={{ opacity: 0, x: 20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="glass-card p-6 md:p-8 hover:border-accent/50 transition-colors group"
          >
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-xl font-display font-semibold text-foreground">Score vs Rank</h3>
                <p className="text-sm text-muted-foreground mt-1">Lower rank is better ΓÇó 2024 vs 2025</p>
              </div>
            </div>
            <div className="h-[300px] md:h-[400px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={data} margin={{ top: 10, right: 10, left: 10, bottom: 0 }}>
                  <defs>
                    <linearGradient id="rankGradient25" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(var(--accent))" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="hsl(var(--accent))" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="rankGradient24" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(var(--muted-foreground))" stopOpacity={0.1} />
                      <stop offset="95%" stopColor="hsl(var(--muted-foreground))" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--muted-foreground)/0.15)" vertical={false} />
                  <XAxis 
                    dataKey="score" 
                    tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 12 }} 
                    axisLine={false} 
                    tickLine={false}
                    label={{ value: "Marks out of 300", position: "insideBottom", offset: -5, fill: "hsl(var(--muted-foreground))" }} 
                  />
                  {/* For rank, lower is better, so we reverse the Y axis visually so high scores = high on chart (rank 1) */}
                  <YAxis 
                    reversed={true} 
                    tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 12 }} 
                    axisLine={false} 
                    tickLine={false} 
                    tickFormatter={(value) => value > 1000 ? `${(value/1000).toFixed(0)}k` : value}
                  />
                  <Tooltip content={<CustomTooltip />} cursor={{ stroke: 'hsl(var(--border))', strokeWidth: 2, strokeDasharray: '5 5' }} />
                  <Legend wrapperStyle={{ paddingTop: '20px' }} />
                  
                  <Area 
                    type="monotone" 
                    dataKey="rank24" 
                    name="2024 Rank" 
                    stroke="hsl(var(--muted-foreground))" 
                    strokeDasharray="4 4"
                    fillOpacity={1} 
                    fill="url(#rankGradient24)" 
                    strokeWidth={2}
                  />
                  <Area 
                    type="monotone" 
                    dataKey="rank25" 
                    name="2025 Rank" 
                    stroke="hsl(var(--accent))" 
                    fillOpacity={1} 
                    fill="url(#rankGradient25)" 
                    strokeWidth={3}
                    activeDot={{ r: 6, strokeWidth: 0, fill: "hsl(var(--accent))" }} 
                  />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </motion.div>
        </div>
      </div>
    </section>
  );
};

export default AnalyticsSection;

import { useState, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ListOrdered, CheckCircle2, Lock, Sparkles, ChevronRight, GraduationCap } from "lucide-react";
import PaymentModal from "./PaymentModal";
import { collegesData } from "@/lib/collegeDatabase";

const STATES = [
  "Andaman and Nicobar Islands", "Andhra Pradesh", "Arunachal Pradesh", "Assam", "Bihar", "Chandigarh", "Chhattisgarh", "Dadra and Nagar Haveli", "Daman and Diu", "Delhi", "Goa", "Gujarat", "Haryana", "Himachal Pradesh", "Jammu and Kashmir", "Jharkhand", "Karnataka", "Kerala", "Ladakh", "Lakshadweep", "Madhya Pradesh", "Maharashtra", "Manipur", "Meghalaya", "Mizoram", "Nagaland", "Odisha", "Puducherry", "Punjab", "Rajasthan", "Sikkim", "Tamil Nadu", "Telangana", "Tripura", "Uttar Pradesh", "Uttarakhand", "West Bengal"
].sort();
const CATEGORIES = ["General", "OBC", "SC", "ST"] as const;

const ChoiceFillingGenerator = () => {
  const [rank, setRank] = useState("");
  const [state, setState] = useState(STATES[0]);
  const [category, setCategory] = useState<typeof CATEGORIES[number]>("General");
  const [paymentOpen, setPaymentOpen] = useState(false);
  const [generatedList, setGeneratedList] = useState<any[] | null>(null);

  const handleGenerate = () => {
    if (!rank) return;
    const numRank = parseInt(rank);

    // Simulate complex AI assortment of safe, target, and reach colleges
    // for demonstration/marketing purposes.
    const sortedColleges = collegesData
      .flatMap(college => {
        return college.branches2024.map(branch => {
          let cutoff = branch.generalCR;
          if (category === "OBC") cutoff = branch.obcCR;
          if (category === "SC") cutoff = branch.scCR;
          if (category === "ST") cutoff = branch.stCR;

          // Home state advantage logic (approx)
          if (college.state === state && college.type === "NIT") {
            cutoff = Math.floor(cutoff * 1.5);
          }

          return {
            college: college.name,
            type: college.type,
            branch: branch.branch,
            cutoff,
            margin: ((cutoff - numRank) / numRank) * 100
          };
        });
      })
      .filter(item => item.cutoff > 0 && item.margin > -20) // Only slightly out of reach or better
      .sort((a, b) => a.cutoff - b.cutoff); // Real JoSAA requires rigid ranking by cutoff OR prestige

    setGeneratedList(sortedColleges.slice(0, 50)); // Generate top 50 choices
  };

  return (
    <section id="choice-filling" className="py-20 relative overflow-hidden bg-background">
      <div className="absolute inset-x-0 -top-40 -z-10 transform-gpu overflow-hidden blur-3xl sm:-top-80" aria-hidden="true">
        <div className="relative left-[calc(50%-11rem)] aspect-[1155/678] w-[36.125rem] -translate-x-1/2 rotate-[30deg] bg-gradient-to-tr from-accent to-[#9089fc] opacity-20 sm:left-[calc(50%-30rem)] sm:w-[72.1875rem]" style={{ clipPath: 'polygon(74.1% 44.1%, 100% 61.6%, 97.5% 26.9%, 85.5% 0.1%, 80.7% 2%, 72.5% 32.5%, 60.2% 62.4%, 52.4% 68.1%, 47.5% 58.3%, 45.2% 34.5%, 27.5% 76.7%, 0.1% 64.9%, 17.9% 100%, 27.6% 76.8%, 76.1% 97.7%, 74.1% 44.1%)' }}></div>
      </div>

      <PaymentModal isOpen={paymentOpen} onClose={() => setPaymentOpen(false)} />

      <div className="container mx-auto px-4 relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-12"
        >
          <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-accent/10 border border-accent/20 text-accent text-xs font-semibold uppercase tracking-wider mb-4">
            <Sparkles className="w-3.5 h-3.5" />
            Premium Feature
          </div>
          <h2 className="text-3xl md:text-5xl font-display font-bold text-foreground mb-4">
            Auto-Generate <span className="text-accent">Choice Filling</span>
          </h2>
          <p className="text-muted-foreground max-w-2xl mx-auto">
            A single mistake in your JoSAA preference order can cost you an IIT seat. Our AI algorithm mathematically generates the perfect, risk-free preference list tailored to your exact rank and state.
          </p>
        </motion.div>

        <div className="max-w-4xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Input Interface */}
